import { useCallback, useEffect, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import type { OpenOrder, DcaOrder } from '../types';

export interface UseOpenOrdersReturn {
  limitOrders: OpenOrder[];
  dcaOrders: DcaOrder[];
  isLoading: boolean;
  error: string | null;
  refresh: () => Promise<void>;
  cancelOrder: (orderId: string, maker: string) => Promise<{ transaction: string }>;
}

export function useOpenOrders(walletAddress: string | null): UseOpenOrdersReturn {
  const api = useTradeApi();
  const [limitOrders, setLimitOrders] = useState<OpenOrder[]>([]);
  const [dcaOrders, setDcaOrders] = useState<DcaOrder[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    if (!walletAddress) return;
    setIsLoading(true); setError(null);
    try {
      const r = await api.getOpenOrders(walletAddress);
      setLimitOrders(r.limitOrders);
      setDcaOrders(r.dcaOrders);
    } catch (e: any) { setError(e.message); }
    finally { setIsLoading(false); }
  }, [api, walletAddress]);

  useEffect(() => { refresh(); }, [refresh]);

  const cancelOrder = useCallback(async (orderId: string, maker: string) => {
    const result = await api.cancelOrder(orderId, maker);
    await refresh();
    return result;
  }, [api, refresh]);

  return { limitOrders, dcaOrders, isLoading, error, refresh, cancelOrder };
}
