import React, { createContext, useContext, useMemo } from 'react';
import { TradeApiClient } from '../utils/apiClient';
import type { CedrosTradeConfig } from '../types';

interface TradeContextValue {
  api: TradeApiClient;
  config: CedrosTradeConfig;
}

const TradeContext = createContext<TradeContextValue | null>(null);

export interface CedrosTradeProviderProps {
  config: CedrosTradeConfig;
  children: React.ReactNode;
}

export function CedrosTradeProvider({ config, children }: CedrosTradeProviderProps) {
  const value = useMemo(() => ({
    api: new TradeApiClient(config.serverUrl, config.getAccessToken, config.apiKey),
    config,
  }), [config.serverUrl, config.apiKey]);

  return (
    <TradeContext.Provider value={value}>
      {children}
    </TradeContext.Provider>
  );
}

export function useTradeContext(): TradeContextValue {
  const ctx = useContext(TradeContext);
  if (!ctx) {
    throw new Error('useTradeContext must be used within <CedrosTradeProvider>');
  }
  return ctx;
}

export function useTradeApi(): TradeApiClient {
  return useTradeContext().api;
}
